#include <stdio.h>
#include <stdlib.h>
#include <string.h>

unsigned int reverseBits(unsigned int x, int k) {
    unsigned int rev = 0;
    for (int i = 0; i < k; ++i) {
        rev = (rev << 1) | (x & 1);
        x >>= 1;
    }
    return rev;
}

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int k; 
        if (scanf("%d", &k) != 1) break;
        int n = 1 << k;
        char *s = (char*)malloc(n + 1);
        char *out = (char*)malloc(n + 1);
        scanf("%s", s);
        for (int i = 0; i < n; ++i) {
            unsigned int rev = reverseBits(i, k);
            out[rev] = s[i];
        }
        out[n] = '\0';
        printf("%s\n", out);
        free(s);
        free(out);
    }
    return 0;
}

